INSERT INTO style_classifications (classification_id, listing_id, photo_url, primary_style, color_tone, price_feel, furniture_density, natural_light, renovation_level, floor_plan, kitchen_style, bathroom_finish, confidence, classified_at, reasoning) VALUES ('01aa3724-e9d2-430a-9087-e660e9c4f318', 'rf_73504731', 'https://ssl.cdn-redfin.com/photo/52/bigphoto/731/73504731_0.jpg', 'Lived-in', 'cool', 'budget', 'moderate', 'medium', 'original', 'closed', 'transitional', 'basic', 0.949999988079071, '2026-04-28 20:12:43.808813+00:00', 'Analyzed 10 interior photos, all of which display strong characteristics of a ''Lived-in'' property rather than professional staging. Key indicators include the presence of personal belongings (coats, shoes, books, toiletries), mismatched and functional furniture, visible clutter on surfaces, and an overall layout geared towards daily life, not for show. The kitchen and bathroom appear to have original, basic-grade finishes.') ON CONFLICT DO NOTHING;
