INSERT INTO style_classifications (classification_id, listing_id, photo_url, primary_style, color_tone, price_feel, furniture_density, natural_light, renovation_level, floor_plan, kitchen_style, bathroom_finish, confidence, classified_at, reasoning) VALUES ('e42cfbdf-c28e-4af3-aa2e-32b1dd6ff231', 'rf_73468924', 'https://ssl.cdn-redfin.com/photo/52/bigphoto/924/73468924_0.jpg', 'Unclassified', 'neutral', 'budget', 'moderate', 'medium', 'original', 'closed', 'traditional', 'basic', 0.10000000149011612, '2026-04-28 19:33:23.183262+00:00', 'Analyzed over 10 photos, all of which are exterior shots of the house, yard, and garage. There are zero interior photos provided. According to the rules, when all photos are exterior shots and the interior cannot be seen, the style must be classified as ''Unclassified''. All other attributes are inferred based on the exterior appearance of an older home or set to default values due to the lack of information.') ON CONFLICT DO NOTHING;
INSERT INTO style_classifications (classification_id, listing_id, photo_url, primary_style, color_tone, price_feel, furniture_density, natural_light, renovation_level, floor_plan, kitchen_style, bathroom_finish, confidence, classified_at, reasoning) VALUES ('07959062-194c-473b-8dd5-beaa225c6986', 'rf_73487237', 'https://ssl.cdn-redfin.com/photo/52/bigphoto/237/73487237_0.jpg', 'EmptyRoom', 'neutral', 'mid', 'sparse', 'high', 'full', 'open', 'transitional', 'updated', 0.9800000190734863, '2026-04-28 19:47:09.900494+00:00', 'Based on the analysis of 6 indoor photos (1 kitchen, 2 living room, 2 bedroom, 1 bathroom), the property is clearly vacant. The living rooms and bedrooms are completely devoid of furniture, showcasing only the floors and walls. The kitchen and bathroom, while containing new fixtures, are also empty of any personal items or staging decor. The property has undergone a full, modern renovation, but is presented without any staging. Therefore, the primary classification is EmptyRoom.') ON CONFLICT DO NOTHING;
INSERT INTO style_classifications (classification_id, listing_id, photo_url, primary_style, color_tone, price_feel, furniture_density, natural_light, renovation_level, floor_plan, kitchen_style, bathroom_finish, confidence, classified_at, reasoning) VALUES ('615422d1-ff25-4534-98a9-2b335b98de96', 'rf_73487355', 'https://ssl.cdn-redfin.com/photo/52/bigphoto/355/73487355_1.jpg', 'Lived-in', 'warm', 'budget', 'moderate', 'low', 'original', 'closed', 'traditional', 'basic', 0.949999988079071, '2026-04-28 19:47:43.418462+00:00', 'Based on 6 interior photos of the unit, the property is definitively classified as ''Lived-in''. There are numerous strong signals of current occupancy, including an unmade bed, personal items and clutter on nearly every surface (desk, coffee table, dining table), shoes by the door, and functional, non-staged furniture. The space lacks the polished, impersonal feel of professional staging.') ON CONFLICT DO NOTHING;
INSERT INTO style_classifications (classification_id, listing_id, photo_url, primary_style, color_tone, price_feel, furniture_density, natural_light, renovation_level, floor_plan, kitchen_style, bathroom_finish, confidence, classified_at, reasoning) VALUES ('5c491996-ed4d-4c4a-9998-21e0b067b8ab', 'rf_73493658', 'https://ssl.cdn-redfin.com/photo/52/bigphoto/658/73493658_0.jpg', 'Lived-in', 'warm', 'budget', 'dense', 'medium', 'original', 'closed', 'traditional', 'basic', 0.9800000190734863, '2026-04-28 19:59:09.379248+00:00', 'Analyzed 8 distinct interior photos (excluding exteriors and duplicates). All furnished rooms exhibit strong ''Lived-in'' characteristics, negating a professional staging classification. Key evidence includes abundant personal items (car posters, eclectic art collections, music equipment, vintage cameras), visible clutter on kitchen counters and desks, and non-matching furniture that reflects personal taste rather than a curated design. The kitchens feature dated, traditional-style oak cabinets and basic appliances, suggesting a budget price point and original renovation level. No bathroom photos were provided, so the ''basic'' finish is inferred from the overall condition of the unit.') ON CONFLICT DO NOTHING;
