INSERT INTO style_classifications (classification_id, listing_id, photo_url, primary_style, color_tone, price_feel, furniture_density, natural_light, renovation_level, floor_plan, kitchen_style, bathroom_finish, confidence, classified_at, reasoning) VALUES ('11916771-dfa7-43b6-a650-421b8541470a', 'rf_73505155', 'https://ssl.cdn-redfin.com/photo/52/bigphoto/155/73505155_1.jpg', 'Lived-in', 'warm', 'budget', 'dense', 'high', 'partial', 'closed', 'traditional', 'updated', 0.949999988079071, '2026-04-28 20:14:38.112496+00:00', 'Analyzed 10 consistent interior photos (ignoring one outlier luxury photo that appears to be from a different property). The ''Lived-in'' classification is based on overwhelming evidence of personal occupancy, including hobby equipment (DJ decks, exercise bike), personal decor (band and slogan flags, beer signs), visible clutter (boxes, clothes, electronics), and uncoordinated, functional furniture throughout the home. This is clearly a tenant/owner-occupied space, not professionally staged.') ON CONFLICT DO NOTHING;
